<span class="line"><span style="color:#89B4FA;font-style:italic;">                println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;  </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> (</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> bytes)&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> entry</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">path</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">display</span><span style="color:#9399B2;">(),</span><span style="color:#CDD6F4;"> entry</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">size_bytes</span><span style="color:#9399B2;">);</span></span>
